import{_ as s,c as i,o as t,ag as e}from"./chunks/framework.DPDPlp3K.js";const l="/assets/ssl-error.DSuGNq_r.png",o="/assets/PixPin_2024-10-17_03-37-35.Cmu7FQK0.png",m=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"faq.md","filePath":"faq.md","lastUpdated":1741625350000}'),r={name:"faq.md"};function n(d,a,p,c,h,k){return t(),i("div",null,a[0]||(a[0]=[e('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><nav class="table-of-contents"><ul><li><a href="#episode-error">集数识别错误</a></li><li><a href="#auto-rename">自动重命名不生效</a></li><li><a href="#ssl-error">SSL握手异常</a></li><li><a href="#collection">老番合集整理</a></li><li><a href="#qb-download-error">qBittorrent 下载时出现错误</a></li><li><a href="#windows-port-error">Windows 端口被占用</a></li><li><a href="#qb-config">qBittorrent 未配置完成</a></li><li><a href="#update-error">为什么程序的自更新无法使用</a></li><li><a href="#auto-skip">自动跳过无法生效</a></li><li><a href="#开启备用rss后自动洗版无法自动删除旧的视频">开启备用RSS后自动洗版无法自动删除旧的视频</a></li><li><a href="#items-delete">删除了视频 在预览中还是显示本地存在</a></li><li><a href="#为什么没有第x集">为什么没有第X集</a></li><li><a href="#download-v2">不会自动下载某集的v2、v3版本, 并覆盖老版本</a></li><li><a href="#nsfw">有些NSFW番剧无法解析</a></li></ul></nav><h2 id="episode-error" tabindex="-1">集数识别错误 <a class="header-anchor" href="#episode-error" aria-label="Permalink to &quot;集数识别错误 { id=episode-error }&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">INFO</p><ul><li>开启 <a href="./add-rss.html#custom-episode">自定义集数规则</a></li><li>如果默认的集数规则也无法识别可以自己修改正则</li><li>如果不会正则的可以让ai生成</li></ul><p><a href="https://www.runoob.com/regexp/regexp-tutorial.html" target="_blank" rel="noreferrer">菜鸟教程-正则表达式</a></p></div><h2 id="auto-rename" tabindex="-1">自动重命名不生效 <a class="header-anchor" href="#auto-rename" aria-label="Permalink to &quot;自动重命名不生效 { id=auto-rename }&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">INFO</p><ul><li>如果使用的 <strong>aria2</strong>, 需要 <strong>ani-rss</strong> 与 <strong>aria2</strong> 的 <strong>docker</strong> 挂载路径一致</li><li>确保 <strong>qBittorrent</strong> 版本在 <strong>4.6.11</strong> 以上</li><li>确保 <a href="./config/basic.html#rename-template">重命名模版</a> 包含 <code>S${seasonFormat}E${episodeFormat}</code> 这样的格式</li></ul></div><h2 id="ssl-error" tabindex="-1">SSL握手异常 <a class="header-anchor" href="#ssl-error" aria-label="Permalink to &quot;SSL握手异常 { id=ssl-error }&quot;">​</a></h2><p><img src="'+l+`" alt="ssl-error.png" loading="lazy"></p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>这个就是网络问题, 频率不频繁的话 <strong>可以无视</strong>。使用镜像站或者选择 <code>https://mikanani.me</code> 域名配合代理使用可以缓解</p><p>镜像站推荐 <code>https://mikan.sakiko.de/</code></p></div><h2 id="collection" tabindex="-1">老番合集整理 <a class="header-anchor" href="#collection" aria-label="Permalink to &quot;老番合集整理 { id=collection }&quot;">​</a></h2><p>部分较老的番剧已经没人做种了, 只有合集才能下载的动。</p><p>因为现有代码逻辑原因 <code>ani-rss</code> 并不打算支持合集整理功能</p><p>推荐使用:</p><p><a href="https://github.com/EstrellaXD/Auto_Bangumi" target="_blank" rel="noreferrer">AutoBangumi</a> 、 <a href="https://github.com/jxxghp/MoviePilot" target="_blank" rel="noreferrer">MoviePilot</a> 、 <a href="https://github.com/Nriver/Episode-ReName" target="_blank" rel="noreferrer">Episode-ReName</a></p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>排名不分前后</p></div><h2 id="qb-download-error" tabindex="-1">qBittorrent 下载时出现错误 <a class="header-anchor" href="#qb-download-error" aria-label="Permalink to &quot;qBittorrent 下载时出现错误 { id=qb-download-error }&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">INFO</p><p>大概率为权限问题</p><p>修改 qb 容器的 <code>PUID</code> 与 <code>GUID</code> 为 <code>0</code></p><p>或者</p><p>使用命令赋予文件夹权限</p></div><details class="details custom-block"><summary>使用命令赋予文件夹权限</summary><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 777</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /Media</span></span></code></pre></div></details><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>如果还未解决请自行查看 qBittorrent 日志进行排查</p></div><h2 id="windows-port-error" tabindex="-1">Windows 端口被占用 <a class="header-anchor" href="#windows-port-error" aria-label="Permalink to &quot;Windows 端口被占用 { id=windows-port-error }&quot;">​</a></h2><div class="language-log vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">log</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">BindException</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: Address already in use: bind</span></span></code></pre></div><p>可能是 Hyper-V 随机占用端口导致的</p><p>具体原因可以Bing <a href="https://www.bing.com/search?q=Hyper-V%E9%9A%8F%E6%9C%BA%E5%8D%A0%E7%94%A8%E7%AB%AF%E5%8F%A3" target="_blank" rel="noreferrer">https://www.bing.com/search?q=Hyper-V随机占用端口</a></p><p><strong>以下有两种解决方法</strong></p><details class="details custom-block"><summary>修改Hyper-V动态端口解决</summary><p>可以通过以下命令去调整 TCP 动态端口范围</p><div class="language-bat vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bat</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">netsh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> int ipv4 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">set</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> dynamic tcp start</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">55000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> num=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10536</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">netsh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> int ipv6 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">set</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> dynamic tcp start</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">55000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> num=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10536</span></span></code></pre></div><p>此时重启电脑，Hyper-V 就会从 55000 - 65565 范围内选取一些端口进行占用，而不会占用日常开发的端口。</p></details><details class="details custom-block"><summary>修改程序端口解决</summary><p>可通过创建快捷方式并添加参数修改端口号</p><div class="language-md vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">md</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--port [端口号 如 13888]</span></span></code></pre></div><img src="`+o+'" alt="PixPin_2024-10-17_03-37-35.png" width="300"></details><h2 id="qb-config" tabindex="-1">qBittorrent 未配置完成 <a class="header-anchor" href="#qb-config" aria-label="Permalink to &quot;qBittorrent 未配置完成 { id=qb-config }&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">INFO</p><p>是否已配置下载器的 <strong>地址、用户名、密码 和 下载位置</strong></p></div><h2 id="update-error" tabindex="-1">为什么程序的自更新无法使用 <a class="header-anchor" href="#update-error" aria-label="Permalink to &quot;为什么程序的自更新无法使用 {id=update-error}&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">INFO</p><p>更新时使用的是 <a href="https://github.com" target="_blank" rel="noreferrer">Github</a>, 请检查你的网络条件</p></div><h2 id="auto-skip" tabindex="-1">自动跳过无法生效 <a class="header-anchor" href="#auto-skip" aria-label="Permalink to &quot;自动跳过无法生效 { id=auto-skip }&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">INFO</p><p>请确保 <strong>ani-rss</strong> 和 <strong>qBittorrent</strong> 的映射位置一致</p></div><h2 id="开启备用rss后自动洗版无法自动删除旧的视频" tabindex="-1">开启备用RSS后自动洗版无法自动删除旧的视频 <a class="header-anchor" href="#开启备用rss后自动洗版无法自动删除旧的视频" aria-label="Permalink to &quot;开启备用RSS后自动洗版无法自动删除旧的视频&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">INFO</p><ul><li>请确保 <strong>ani-rss</strong> 和 <strong>qBittorrent</strong> 的映射位置一致</li><li>请关闭❌ <a href="./config/basic.html#auto-skip">自动跳过</a></li><li>请开启✅ <a href="./config/download.html#auto-delete">自动删除</a></li></ul></div><h2 id="items-delete" tabindex="-1">删除了视频 在预览中还是显示本地存在 <a class="header-anchor" href="#items-delete" aria-label="Permalink to &quot;删除了视频 在预览中还是显示本地存在 { id=items-delete }&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">INFO</p><p>在预览界面删除对应的种子缓存</p></div><h2 id="为什么没有第x集" tabindex="-1">为什么没有第X集 <a class="header-anchor" href="#为什么没有第x集" aria-label="Permalink to &quot;为什么没有第X集&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">INFO</p><ul><li>检查源rss是否包含该集</li><li>检查排除规则</li></ul></div><h2 id="download-v2" tabindex="-1">不会自动下载某集的v2、v3版本, 并覆盖老版本 <a class="header-anchor" href="#download-v2" aria-label="Permalink to &quot;不会自动下载某集的v2、v3版本, 并覆盖老版本 { id=download-v2 }&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">INFO</p><ul><li>请关闭❌ <a href="./config/basic.html#auto-skip">自动跳过</a></li><li>请开启✅ <a href="./config/download.html#auto-delete">自动删除</a></li></ul></div><h2 id="nsfw" tabindex="-1">有些NSFW番剧无法解析 <a class="header-anchor" href="#nsfw" aria-label="Permalink to &quot;有些NSFW番剧无法解析 { id=nsfw }&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">INFO</p><p>请在设置中完善 <a href="./config/basic.html#bgmtoken">BgmToken</a></p></div>',42)]))}const b=s(r,[["render",n]]);export{m as __pageData,b as default};
